export function getModelProfile(name: string): ModelProfile {
  const fallback = `https://api.dicebear.com/9.x/initials/svg?seed=${encodeURIComponent(name)}&backgroundColor=111111&textColor=ffffff`;
  const base = modelProfiles[name] ?? {
    image: fallback,
    bio: `${name} is a featured model on NAKED GIRLS, known for a refined presence in premium fashion and lifestyle features. Expect a distinctive style and consistently editorial-grade content.`,
  };
  return {
    ...base,
    card: base.card ?? base.image,
    hero: base.hero ?? base.image,
    portrait: base.portrait ?? base.image,
  };
}

export function slugifyModel(name: string): string {
  return name.toLowerCase().replace(/\s+/g, "-").replace(/[^a-z0-9-]/g, "");
}

export function unslugifyModel(slug: string): string | null {
  const target = slug.toLowerCase();
  return modelCodes.find((m) => slugifyModel(m) === target) ?? null;
}

export function getVideoEmbedUrl(src: string): string {
  let url = "";
  if (src.startsWith("http://") || src.startsWith("https://")) url = src;
  else if (src.startsWith("//")) url = `https:${src}`;
  else url = `https://${src.replace(/^\/+/, "")}`;

  // If it's already an embed link (has /e/), normalize the domain
  // Mixdrop domains change often, here are common ones found in data
  if (url.includes("/e/") || url.includes("mixdrop") || url.includes("mxdrop")) {
    url = url.replace(/(?:mix|mx|md)drop\.(?:sx|top|co|to|bz|ag|ch|vc|st|ps|io|net|gl|ch)/g, "mixdrop.ps");
  }

  // If it's a mixdrop ID but not a full URL
  if (!url.includes("/") && url.length >= 10 && url.length <= 16) {
    url = `https://mixdrop.ps/e/${url}`;
  }

  // Ensure mixdrop links have /e/ for embedding if they are direct file links
  if (url.includes("mixdrop.ps") && !url.includes("/e/")) {
    url = url.replace("mixdrop.ps/f/", "mixdrop.ps/e/");
  }

  return url;
}

export function getVideoThumbnailUrl(thumb: string | undefined): string {
  if (!thumb) return "";
  if (thumb.startsWith("//")) return `https:${thumb}`;
  return thumb;
}

export function getThumbnailAspectRatio(thumb: string | undefined): string {
  // Stripchat, damplips, and ibb.co thumbnails are typically 16:9
  if (
    thumb && (
      thumb.includes("damplips.com") || 
      thumb.includes("ibb.co") || 
      thumb.toLowerCase().includes("stripchat")
    )
  ) {
    return "aspect-video";
  }
  // Default to 16:9 as well as it's more standard for the 340x191 request
  return "aspect-video";
}

export function formatDate(dateStr: string): string {
  try {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  } catch {
    return dateStr;
  }
}

export function formatDuration(seconds: string | number | undefined): string {
  if (!seconds) return "0:00";
  
  if (typeof seconds === 'string' && seconds.includes(':')) {
    return seconds;
  }
  
  const s = typeof seconds === 'number' ? seconds : parseInt(seconds, 10);
  if (isNaN(s)) return typeof seconds === 'string' ? seconds : "0:00";
  
  const m = Math.floor(s / 60);
  const rem = s % 60;
  return `${m}:${rem.toString().padStart(2, "0")}`;
}

/**
 * Format views in 'k' format with one decimal place.
 * Example: 10400 -> 10.4k
 */
export function formatViews(count: number): string {
  if (count >= 1000) {
    return (count / 1000).toFixed(1) + "k";
  }
  return count.toString();
}

/**
 * Deterministically generate a unique-feeling view count in the thousands (10k - 100k)
 */
export function getViews(seed: string): string {
  // FNV-1a hash for better distribution
  let h = 0x811c9dc5;
  for (let i = 0; i < seed.length; i++) {
    h ^= seed.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  
  // Extra mixing for higher entropy/variance
  h ^= h >>> 16;
  h = Math.imul(h, 0x85ebca6b);
  h ^= h >>> 13;
  h = Math.imul(h, 0xc2b2ae35);
  h ^= h >>> 16;

  const positive = Math.abs(h);
  // Generate a number between 10,000 and 100,000
  const count = 10000 + (positive % 90001);
  return formatViews(count);
}

// Returns the list of models for a video. Supports comma/&/+ separated names
// in the `model` field (e.g. "Eliza Ibarra & Mick Blue").
export function getVideoModels(v: { model?: string }): string[] {
  if (!v.model) return [];
  return v.model
    .split(/\s*(?:,|&|\+|\/| and )\s*/i)
    .map((m) => m.trim())
    .filter(Boolean);
}

export function videoHasModel(v: { model?: string }, name: string): boolean {
  return getVideoModels(v).some((m) => m.toLowerCase() === name.toLowerCase());
}
